// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/data/models/dto/player/handedness.dart';
import 'package:baseball_detector_flutter/data/models/failure/bad_request_failure.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/repository_provider.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_dialog.dart';
import 'package:baseball_detector_flutter/views/hooks/use_operation.dart';
import 'package:baseball_detector_flutter/views/hooks/use_widget_ref.dart';
import 'package:baseball_detector_flutter/views/pages/home/hooks/use_ai_coach_count.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/hooks/use_session_refresh.dart';

Future<void> Function({
  required List<Ball> hittingBalls,
  required List<Ball> pitchingBalls,
  bool shouldShowCautionDialog,
}) useAIReportGeneration({
  required Player? player,
  required ValueNotifier<Session> currentSession,
}) {
  final context = useContext();
  final ref = useWidgetRef();
  final repository = ref.watch(repositoryProvider);
  final handleOperation = useOperation<String>();
  final usage = useAICoachCount();

  final onRefresh = useSessionRefresh(currentSession: currentSession);

  return ({
    required List<Ball> hittingBalls,
    required List<Ball> pitchingBalls,
    bool shouldShowCautionDialog = true,
  }) async {
    final sessionId = currentSession.value.id;
    final teamId = currentSession.value.teamId;

    if (sessionId == null || teamId == null) return;

    final hasPitchingBalls = pitchingBalls.isNotEmpty;
    final hasAllPitchTypes = hasPitchingBalls &&
        !pitchingBalls.any(
          (ball) =>
              ball.pitchType == null || ball.pitchType?.pitchType == 'none',
        );

    // 投球データが存在するか
    if (!hasPitchingBalls) {
      context.showErrorSnackBar(
        context.l10n.ai_coach_report__request_need_pitching_data,
      );
      return;
    }

    // すべてに球種タグがついているか
    if (!hasAllPitchTypes) {
      context.showErrorSnackBar(
        context.l10n.ai_coach_report__request_need_pitch_type,
      );
      return;
    }

    // 利き手が設定されているか
    final pitchingHand = player?.pitchingHand ?? Handedness.none;
    if (pitchingHand == Handedness.none) {
      context.showErrorSnackBar(
        context.l10n.ai_coach_report__request_need_player_pitching_hand,
      );
      return;
    }

    // 誕生日が設定されているか
    final hasBirthday = player?.birthday != null;
    if (!hasBirthday) {
      context.showErrorSnackBar(
        context.l10n.ai_coach_report__request_need_player_birthday,
      );
      return;
    }

    // AI コーチの利用回数上限に達していないか
    if (usage.maxUsage != null &&
        usage.currentUsage != null &&
        usage.currentUsage! >= usage.maxUsage!) {
      context.showErrorSnackBar(
        context.l10n.ai_coach_report__request_limit_reached_message,
      );
      return;
    }

    if (shouldShowCautionDialog) {
      final shouldGenerate = await showDialog<bool>(
        context: context,
        barrierDismissible: true,
        builder: (dialogContext) {
          final maxUsageText = usage.maxUsage?.toString() ?? '--';
          final currentUsageText = usage.currentUsage?.toString() ?? '--';

          return CustomDialog.normal(
            title: dialogContext.l10n.ai_coach_report__request_confirm_title,
            builder: (innerContext, _) {
              return Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'AI コーチの利用回数が 1 回加算されます',
                  ),
                  const Gap(16),
                  Text(
                    dialogContext.l10n
                        .ai_coach_report__request_confirm_usage_message(
                      maxUsageText,
                      currentUsageText,
                    ),
                  ),
                ],
              );
            },
            aboveButtonText: dialogContext
                .l10n.ai_coach_report__request_confirm_positive_button_label,
            aboveButtonAction: (actionContext) {
              Navigator.of(actionContext).pop(true);
            },
            belowButtonText: dialogContext
                .l10n.ai_coach_report__request_confirm_negative_button_label,
            belowButtonAction: (actionContext) {
              Navigator.of(actionContext).pop(false);
            },
          );
        },
      );

      if (shouldGenerate != true) return;
    }

    await handleOperation(
      operation:
          repository.createAIReport(teamId: teamId, sessionId: sessionId),
      onSucceeded: (_) async {
        await onRefresh();
        return context.mounted
            ? context.l10n.ai_coach_report__request_success_message
            : null;
      },
      onFailed: (failure) async =>
          context.mounted ? failure.translate(context.l10n) : null,
      shouldSendErrorLog: (failure) =>
          !_ignoreFailure.contains(failure.runtimeType),
    );
  };
}

// エラーログを送らない Failure
const _ignoreFailure = [
  PitchTypeNotTaggedForAllResourcesFailure,
  PlayerBirthdayMissingFailure,
  PlayerThrowHandMissingFailure,
  SessionHasNoResourcesFailure,
];
